PythonJavaGo <pre><code>from strands_agents_jsii import (
    StrandsAgent, AgentConfig,
    BedrockModelProvider, BedrockModelConfig,
    ToolDefinition, ToolSpecification,
)
import json

class Calculator(ToolDefinition):
    def __init__(self):
        super().__init__(ToolSpecification(
            "calculator", "Math evaluator",
            json.dumps({
                "type": "object",
                "properties": {"expression": {"type": "string"}},
                "required": ["expression"]
            })
        ))

    def execute(self, input_json):
        result = eval(json.loads(input_json)["expression"])
        return json.dumps({"result": result})

agent = StrandsAgent(AgentConfig(
    model=BedrockModelProvider(BedrockModelConfig(
        "us.anthropic.claude-sonnet-4-20250514-v1:0", "us-west-2"
    )),
    system_prompt="Use calculator for math.",
    tools=[Calculator()]
))

response = agent.invoke("What is sqrt(256) + 100?")
print(response.text)  # "116"
